styles:
.blog-post { max-width: 700px; margin: 0 auto; padding: 8rem 1.5rem 4rem; }
    .blog-post-header { margin-bottom: 3rem; text-align: center; }
    .blog-post-header h1 { margin-bottom: 1.5rem; }
    .blog-post-meta { display: flex; align-items: center; justify-content: center; gap: 1rem; color: var(--text-muted); font-size: 0.875rem; }
    .blog-post-content { font-size: 1.0625rem; line-height: 1.8; }
    .blog-post-content h2 { margin-top: 2.5rem; margin-bottom: 1rem; }
    .blog-post-content h3 { margin-top: 2rem; margin-bottom: 0.75rem; }
    .blog-post-content p { margin-bottom: 1.5rem; color: var(--text-secondary); }
    .blog-post-content ul, .blog-post-content ol { margin-bottom: 1.5rem; padding-left: 1.5rem; }
    .blog-post-content li { margin-bottom: 0.75rem; color: var(--text-secondary); list-style: disc; }
    .blog-post-content strong { color: var(--text-primary); }
    .blog-post-content a { color: var(--primary); text-decoration: underline; }
    .blog-post-content a:hover { color: var(--primary-dark); }
    .blog-post-tags { display: flex; flex-wrap: wrap; gap: 0.5rem; margin-top: 3rem; padding-top: 2rem; border-top: 1px solid var(--border); }
    .blog-post-tag { padding: 0.25rem 0.75rem; background: var(--bg-tertiary); border-radius: 9999px; font-size: 0.8125rem; color: var(--text-secondary); }
    .blog-post-nav { display: flex; justify-content: space-between; margin-top: 3rem; padding-top: 2rem; border-top: 1px solid var(--border); }
    .blog-post-nav a { color: var(--primary); font-weight: 500; }
    .blog-post-nav a:hover { text-decoration: underline; }
    .callout { background: rgba(99, 102, 241, 0.1); border-left: 4px solid var(--primary); padding: 1.5rem; border-radius: 0 var(--radius) var(--radius) 0; margin: 1.5rem 0; }
    .callout p { margin-bottom: 0; }
